<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3">Fleet Management</h1><p class="text-muted mb-0">Vehicles, mileage, service dates, and operational status.</p></div><button class="btn btn-primary" data-bs-toggle="modal" data-bs-target="#vehicleModal"><i class="fa-solid fa-plus me-2"></i>Add Vehicle</button></div>
<div class="row g-3"><?php foreach($vehicles as $v): ?><div class="col-lg-4"><div class="card h-100"><div class="card-body"><div class="d-flex justify-content-between"><h2 class="h5"><?= e($v['unit_number']) ?></h2><span class="badge text-bg-<?= $v['status']==='active'?'success':($v['status']==='maintenance'?'warning':'secondary') ?>"><?= e(str_replace('_',' ',$v['status'])) ?></span></div><p class="mb-2"><?= e(trim(($v['year']??'').' '.($v['make']??'').' '.($v['model']??''))) ?></p><dl class="row small"><dt class="col-5">Odometer</dt><dd class="col-7"><?= e(number_format((int)($v['odometer']??0))) ?> mi</dd><dt class="col-5">Plate</dt><dd class="col-7"><?= e($v['plate']??'') ?></dd><dt class="col-5">Next service</dt><dd class="col-7"><?= e($v['next_service_date']??'Not set') ?></dd></dl></div></div></div><?php endforeach ?></div>
